#include<cstdio>
#include<map>
#include<vector>
#include<string>
#include<cstdlib>
using namespace std;int W,H,EX,T[99][99],LK[99][99];map<string,string>RM[14];int DX[4]={0,0,-1,1},DY[4]={-1,1,0,0};string DN[]={"TOP","BOTTOM","LEFT","RIGHT"};map<string,string>OPP={{"TOP","BOTTOM"},{"BOTTOM","TOP"},{"LEFT","RIGHT"},{"RIGHT","LEFT"}};map<string,string>CW={{"TOP","RIGHT"},{"RIGHT","BOTTOM"},{"BOTTOM","LEFT"},{"LEFT","TOP"}};map<string,string>rotR(map<string,string>rm){map<string,string>r;for(auto&[e,x]:rm)r[CW[e]]=CW[x];return r;}int di(string s){return s=="TOP"?0:s=="BOTTOM"?1:s=="LEFT"?2:3;}map<int,map<string,string>>rots;map<string,string>gt(int x,int y){return rots.count(y*99+x)?rots[y*99+x]:RM[T[y][x]];}struct Step{int x,y;map<string,string>t;};vector<Step>plan;bool dfs(int x,int y,string e){if(y>=H)return 1;if(x<0||x>=W||y<0)return 0;auto o=RM[T[y][x]];vector<map<string,string>>cs;if(LK[y][x])cs={gt(x,y)};else{auto t=o;for(int i=0;i<4;i++){cs.push_back(t);t=rotR(t);}}int k=y*99+x;for(auto&c:cs){if(!c.count(e))continue;auto ex=c[e];int nx=x+DX[di(ex)],ny=y+DY[di(ex)];auto ne=OPP[ex];auto prev=rots.count(k)?rots[k]:map<string,string>{};bool had=rots.count(k);rots[k]=c;if(dfs(nx,ny,ne)){if(c!=RM[T[y][x]])plan.push_back({x,y,c});return 1;}if(had)rots[k]=prev;else rots.erase(k);}return 0;}vector<string>Q;int main(){scanf("%d%d",&W,&H);RM[0]={};RM[1]={{"TOP","BOTTOM"},{"LEFT","BOTTOM"},{"RIGHT","BOTTOM"}};RM[2]={{"TOP","RIGHT"},{"RIGHT","BOTTOM"}};RM[3]={{"TOP","LEFT"},{"LEFT","BOTTOM"}};RM[4]={{"TOP","LEFT"},{"LEFT","BOTTOM"}};RM[5]={{"TOP","RIGHT"},{"RIGHT","BOTTOM"}};RM[6]={{"TOP","RIGHT"},{"LEFT","BOTTOM"}};RM[7]={{"TOP","LEFT"},{"RIGHT","BOTTOM"}};RM[8]={{"LEFT","BOTTOM"},{"RIGHT","TOP"}};RM[9]={{"RIGHT","BOTTOM"},{"LEFT","TOP"}};RM[10]={{"LEFT","RIGHT"},{"RIGHT","LEFT"}};RM[11]={{"TOP","BOTTOM"},{"BOTTOM","TOP"}};RM[12]={{"TOP","RIGHT"},{"RIGHT","TOP"},{"LEFT","BOTTOM"},{"BOTTOM","LEFT"}};RM[13]={{"TOP","LEFT"},{"LEFT","TOP"},{"RIGHT","BOTTOM"},{"BOTTOM","RIGHT"}};for(int y=0;y<H;y++)for(int x=0;x<W;x++){scanf("%d",&T[y][x]);LK[y][x]=T[y][x]<0;T[y][x]=abs(T[y][x]);}scanf("%d",&EX);for(;;){int xi,yi;char ent[9];scanf("%d%d%s",&yi,&xi,ent);int R;scanf("%d",&R);for(int i=0;i<R;i++){int a,b;char d[9];scanf("%d%d%s",&a,&b,d);}if(Q.empty()){rots.clear();plan.clear();if(dfs(xi,yi,string(ent))){for(auto&s:plan){auto o=RM[T[s.y][s.x]];int r=0;auto t=o;for(int i=0;i<4;i++){if(t==s.t){r=i;break;}t=rotR(t);}if(!r)continue;const char*d=r<=2?"RIGHT":"LEFT";int cnt=r<=2?r:4-r;for(int i=0;i<cnt;i++){char buf[20];sprintf(buf,"%d %d %s",s.x,s.y,d);Q.push_back(buf);}T[s.y][s.x]=0;/* mark as changed */}}}if(!Q.empty()){puts(Q[0].c_str());Q.erase(Q.begin());}else puts("WAIT");fflush(stdout);}}